import { Graph } from '@antv/x6';

const graph = new Graph({
  container: 'container',
  background: {
    color: '#F2F7FA',
  },
  grid: {
    visible: true,
    type: 'doubleMesh',
    args: [
      {
        color: '#eee',
        thickness: 1,
      },
      {
        color: '#ddd',
        thickness: 1,
        factor: 4,
      },
    ],
  },
  panning: true,
  mousewheel: {
    enabled: true,
    modifiers: 'Ctrl',
    maxScale: 4,
    minScale: 0.2,
  },
});

const source = graph.addNode({
  shape: 'rect',
  x: 40,
  y: 40,
  width: 100,
  height: 40,
  label: 'Source',
  attrs: {
    body: {
      stroke: '#8f8f8f',
      strokeWidth: 1,
      fill: '#fff',
      rx: 6,
      ry: 6,
    },
  },
});

const target = graph.addNode({
  shape: 'rect',
  x: 200,
  y: 200,
  width: 100,
  height: 40,
  label: 'Target',
  attrs: {
    body: {
      stroke: '#8f8f8f',
      strokeWidth: 1,
      fill: '#fff',
      rx: 6,
      ry: 6,
    },
  },
});

graph.addEdge({
  source,
  target,
  attrs: {
    line: {
      stroke: '#8f8f8f',
      strokeWidth: 1,
    },
  },
});

graph.zoomToFit();
graph.centerContent();

import { Graph } from '@antv/x6';

Graph.registerNode(
  'custom-node',
  {
    inherit: 'rect',
    width: 100,
    height: 40,
    markup: [
      {
        tagName: 'rect',
        selector: 'body',
      },
      {
        tagName: 'image',
        selector: 'img',
      },
      {
        tagName: 'text',
        selector: 'label',
      },
    ],
    attrs: {
      body: {
        stroke: '#8f8f8f',
        strokeWidth: 1,
        fill: '#fff',
        rx: 6,
        ry: 6,
      },
      img: {
        'xlink:href': 'https://gw.alipayobjects.com/zos/antfincdn/FLrTNDvlna/antv.png',
        width: 16,
        height: 16,
        x: 12,
        y: 12,
      },
    },
  },
  true,
);

