import { Graph } from '@antv/x6';

const graph = new Graph({
  container: 'container',
  background: {
    color: '#F2F7FA',
  },
});

const markers = ['block', 'classic', 'diamond', 'circle', 'circlePlus', 'ellipse', 'cross', 'async'];

markers.forEach((marker, i) => {
  graph.addEdge({
    sourcePoint: [120, 20 + i * 40],
    targetPoint: [400, 20 + i * 40],
    label: marker,
    attrs: {
      line: {
        sourceMarker: marker,
        targetMarker: marker,
        stroke: '#8f8f8f',
        strokeWidth: 1,
      },
    },
  });
});

