  const ports = node.getPorts();
  ports.forEach((port) => {
    node.portProp(port.id, 'attrs/circle/style/visibility', 'visible');
  });
});

graph.on('node:mouseleave', ({ node }) => {
  const ports = node.getPorts();
  ports.forEach((port) => {
    node.portProp(port.id, 'attrs/circle/style/visibility', 'hidden');
  });
});

