const padding = 20;

graph.on('node:change:position', ({ node, options }) => {
  if (options.skipParentHandler) return;
  const nodeParent = node.getParent();
  if (nodeParent && nodeParent.isNode()) {
    let originSize = nodeParent.prop('originSize') || nodeParent.getSize();
    let originPosition = nodeParent.prop('originPosition') || nodeParent.getPosition();
    let x = originPosition.x;
    let y = originPosition.y;
    let cornerX = x + originSize.width;
    let cornerY = y + originSize.height;
    let hasChange = false;
    const children = nodeParent.getChildren();
    if (children) {
      children.forEach((child) => {
        const bbox = child.getBBox().inflate(padding);
        const corner = bbox.getCorner();
        if (bbox.x < x) { x = bbox.x; hasChange = true; }
        if (bbox.y < y) { y = bbox.y; hasChange = true; }
        if (corner.x > cornerX) { cornerX = corner.x; hasChange = true; }
        if (corner.y > cornerY) { cornerY = corner.y; hasChange = true; }
      });
    }
    if (hasChange) {
      nodeParent.prop({ position: { x, y }, size: { width: cornerX - x, height: cornerY - y } }, { skipParentHandler: true });
    }
  }
});

