};

const graph = new Graph({
  container: 'container',
  background: { color: '#F2F7FA' },
});

const nodes = ['Task 1', 'Task 2', 'Task 3', 'Task 4'].map((label, i) => {
  return graph.addNode({
    shape: 'rect',
    x: 40 + (i % 2) * 200,
    y: 40 + Math.floor(i / 2) * 100,
    width: 120,
    height: 45,
    label: label,
    data: { status: 'pending' },
