      body: { stroke: '#8f8f8f', strokeWidth: 2, fill: '#fff', rx: 6, ry: 6 },
    },
  });
});

graph.addEdge({ source: nodes[0], target: nodes[1], attrs: { line: { stroke: '#8f8f8f', strokeWidth: 1, targetMarker: 'classic' } } });
graph.addEdge({ source: nodes[0], target: nodes[2], attrs: { line: { stroke: '#8f8f8f', strokeWidth: 1, targetMarker: 'classic' } } });
graph.addEdge({ source: nodes[1], target: nodes[3], attrs: { line: { stroke: '#8f8f8f', strokeWidth: 1, targetMarker: 'classic' } } });
graph.addEdge({ source: nodes[2], target: nodes[3], attrs: { line: { stroke: '#8f8f8f', strokeWidth: 1, targetMarker: 'classic' } } });

const statusOrder = ['pending', 'running', 'success'];

graph.on('node:click', ({ node }) => {
  const data = node.getData() || {};
  const currentIdx = statusOrder.indexOf(data.status || 'pending');
  const nextStatus = statusOrder[(currentIdx + 1) % statusOrder.length];
  node.setData({ status: nextStatus });
  const colors = statusColors[nextStatus];
  node.attr('body/stroke', colors.stroke);
  node.attr('body/fill', colors.fill);
});

